  1	import * as React from 'react';
  2	import {
  3	  APP_NAMESPACE_ANNOTATION,
  4	  DISCOVERED_APP_NS,
  5	  GITOPS_OPERATOR_NAMESPACE,
  6	} from '@odf/mco/constants';
  7	import { useACMSafeFetch } from '@odf/mco/hooks';
  8	import { DRPlacementControlKind, DRPolicyKind } from '@odf/mco/types';
  9	import {
 10	  queryNamespacesUsingCluster,
 11	  convertSearchResultToK8sResourceCommon,
 12	} from '@odf/mco/utils';
 13	import { NamespaceModel } from '@odf/shared/models';
 14	import { ResourceIcon } from '@odf/shared/resource-link/resource-link';
 15	import { getAnnotations, getName } from '@odf/shared/selectors';
 16	import { getNamespace } from '@odf/shared/selectors';
 17	import {
 18	  RedExclamationCircleIcon,
 19	  StatusIconAndText,
 20	} from '@odf/shared/status';
 21	import { RowComponentType, SelectableTable } from '@odf/shared/table';
 22	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 23	import { isSystemNamespace, sortRows } from '@odf/shared/utils';
 24	import {
 25	  K8sResourceCommon,
 26	  ListPageFilter,
 27	  useListPageFilter,
 28	} from '@openshift-console/dynamic-plugin-sdk';
 29	import { TFunction } from 'react-i18next';
 30	import { Bullseye, Grid, GridItem, Text } from '@patternfly/react-core';
 31	import { Td } from '@patternfly/react-table';
 32	import {
 33	  EnrollDiscoveredApplicationAction,
 34	  EnrollDiscoveredApplicationStateType,
 35	} from '../../utils/reducer';
 36	import './namespace-step.scss';
 37	
 38	export const findAllEligiblePolicies = (
 39	  clusterName: string,
 40	  drPolicies: DRPolicyKind[]
 41	) =>
 42	  // Filter all the polcies which are all matching for the selected cluster.
 43	  drPolicies.filter((policy) => policy.spec.drClusters.includes(clusterName));
 44	
 45	const getProtectedNamespaces = (
 46	  drPlacements: DRPlacementControlKind[],
 47	  policies: DRPolicyKind[]
 48	): string[] => {
 49	  if (!!drPlacements?.length) {
 50	    // Find all the protected namespaces from DRPCs.
 51	    // By comparing the eligible DRPolicies, filtering the DRPCs and protected namespaces for the peer clusters.
 52	    const policyNames: string[] = policies.map(getName);
 53	    return drPlacements.reduce((acc, drpc) => {
 54	      if (policyNames.includes(drpc.spec.drPolicyRef.name)) {
 55	        const namespace = getNamespace(drpc);
 56	        if (namespace === DISCOVERED_APP_NS) {
 57	          // Protected namespaces from discovered DRPC
 58	          acc.push(...(drpc.spec?.protectedNamespaces || []));
 59	        } else if (namespace === GITOPS_OPERATOR_NAMESPACE) {
 60	          // Protected namespaces from ApplicationSet DRPC
 61	          const ns = getAnnotations(drpc)?.[APP_NAMESPACE_ANNOTATION];
 62	          !!ns && acc.push(ns);
 63	        } else {
 64	          // Protected namespaces from Subscription DRPC
 65	          acc.push(namespace);
 66	        }
 67	      }
 68	      return acc;
 69	    }, []);
 70	  } else {
 71	    return [];
 72	  }
 73	};
 74	
 75	const getColumns = (t: TFunction) => [
 76	  {
 77	    columnName: t('Name'),
 78	    sortFunction: (a, b, c) => sortRows(a, b, c, 'metadata.name'),
 79	  },
 80	];
 81	
 82	const TableRow: React.FC<RowComponentType<K8sResourceCommon>> = ({
 83	  row: namespaceObj,
 84	}) => {
 85	  const { t } = useCustomTranslation();
 86	  return (
 87	    <Td dataLabel={getColumns(t)[0].columnName}>
 88	      <ResourceIcon resourceModel={NamespaceModel} />
 89	      {getName(namespaceObj)}
 90	    </Td>
 91	  );
 92	};
 93	
 94	const EmptyRowMessageWrapper: React.FC = ({ children }) => {
 95	  return (
 96	    <Bullseye className="mco-namespace-selection__border pf-v6-u-mt-md pf-v6-u-mb-sm pf-v6-u-h-33vh">
 97	      {children}
 98	    </Bullseye>
 99	  );
100	};
101	
102	const EmptyRowMessage: React.FC = () => {
103	  const { t } = useCustomTranslation();
104	
105	  return (
106	    <EmptyRowMessageWrapper>
107	      {t('There are no namespaces to display.')}
108	    </EmptyRowMessageWrapper>
109	  );
110	};
111	
112	const NoClusterEmptyRowMessage: React.FC = () => {
113	  const { t } = useCustomTranslation();
114	
115	  return (
116	    <EmptyRowMessageWrapper>
117	      {t(
118	        'There are no namespaces to display. Select a cluster first to view namespaces.'
119	      )}
120	    </EmptyRowMessageWrapper>
121	  );
122	};
123	
124	export const NamespaceSelectionTable: React.FC<
125	  NamespaceSelectionTableProps
126	> = ({
127	  namespaces,
128	  clusterName,
129	  policies,
130	  drPlacements,
131	  isValidationEnabled,
132	  dispatch,
133	}) => {
134	  const { t } = useCustomTranslation();
135	
136	  const protectedNamespaces = React.useMemo(() => {
137	    const eligiblePolicies = findAllEligiblePolicies(clusterName, policies);
138	    return getProtectedNamespaces(drPlacements, eligiblePolicies);
139	  }, [drPlacements, clusterName, policies]);
140	
141	  const searchQuery = React.useMemo(
142	    () => queryNamespacesUsingCluster(clusterName),
143	    [clusterName]
144	  );
145	
146	  // ACM search proxy API call
147	  const [searchResult, searchError, searchLoaded] =
148	    useACMSafeFetch(searchQuery);
149	
150	  const userNamespaces: K8sResourceCommon[] = React.useMemo(() => {
151	    if (searchLoaded && !searchError) {
152	      // Converting from search result type to K8sResourceCommon for shared components compatibility.
153	      const allNamespaces = convertSearchResultToK8sResourceCommon(
154	        searchResult?.data.searchResult?.[0]?.items || []
155	      );
156	      // Filtering only user namespaces for the DR protection.
157	      return allNamespaces.filter((namespaceObj) => {
158	        const namespace = getName(namespaceObj);
159	        return (
160	          !isSystemNamespace(namespace) &&
161	          !protectedNamespaces.includes(namespace)
162	        );
163	      });
164	    }
165	    return [];
166	  }, [searchResult, protectedNamespaces, searchLoaded, searchError]);
167	
168	  const [data, filteredData, onFilterChange] =
169	    useListPageFilter(userNamespaces);
170	
171	  const setSelectedNamespaces = (selectedNamespaces: K8sResourceCommon[]) =>
172	    dispatch({
173	      type: EnrollDiscoveredApplicationStateType.SET_NAMESPACES,
174	      payload: selectedNamespaces,
175	    });
176	
177	  const namespaceValidated = isValidationEnabled && !namespaces.length;
178	
179	  return (
180	    <Grid>
181	      <GridItem span={10}>
182	        <Text className="text-muted pf-v6-u-font-size-lg">
183	          {!!clusterName
184	            ? t('{{count}} results found for {{clusterName}}', {
185	                count: userNamespaces.length,
186	                clusterName,
187	              })
188	            : t('0 results found')}
189	        </Text>
190	      </GridItem>
191	      <GridItem span={10}>
192	        <ListPageFilter
193	          data={data}
194	          loaded={searchLoaded}
195	          onFilterChange={onFilterChange}
196	        />
197	        {namespaceValidated && (
198	          <StatusIconAndText
199	            icon={<RedExclamationCircleIcon />}
200	            title={t('Select a namespace')}
201	          />
202	        )}
203	        <SelectableTable<K8sResourceCommon>
204	          className="mco-namespace-selection__table mco-namespace-selection__border pf-v6-u-mt-sm pf-v6-u-mb-sm pf-v6-u-h-33vh"
205	          columns={getColumns(t)}
206	          rows={filteredData}
207	          RowComponent={TableRow}
208	          selectedRows={namespaces}
209	          setSelectedRows={setSelectedNamespaces}
210	          loaded={searchLoaded}
211	          borders={false}
212	          emptyRowMessage={
213	            searchError
214	              ? searchError
215	              : clusterName
216	                ? EmptyRowMessage
217	                : NoClusterEmptyRowMessage
218	          }
219	        />
220	        <Text>
221	          {t(
222	            'This list does not include namespaces where applications are enrolled separately under disaster recovery protection.'
223	          )}
224	        </Text>
225	      </GridItem>
226	    </Grid>
227	  );
228	};
