230	type NamespaceSelectionTableProps = {
231	  namespaces: K8sResourceCommon[];
232	  clusterName: string;
233	  policies: DRPolicyKind[];
234	  drPlacements: DRPlacementControlKind[];
235	  isValidationEnabled: boolean;
236	  dispatch: React.Dispatch<EnrollDiscoveredApplicationAction>;
237	};

